// Ambient module declarations for static asset imports (Vite serves these as URLs).
// Fixes `npx tsc --noEmit` errors for imports like `import logo from './bethel-logo.png'`.
declare module '*.png' {
  const src: string;
  export default src;
}

declare module '*.jpg' {
  const src: string;
  export default src;
}

declare module '*.jpeg' {
  const src: string;
  export default src;
}

declare module '*.svg' {
  const src: string;
  export default src;
}

declare module '*.webp' {
  const src: string;
  export default src;
}
